{
  "name": "BHV'ers van BHV land",
  "description": "Een assessment en quiz applicatie voor BHV-teams om vaardigheden te beoordelen en grondstoffen te verdienen door middel van kennisvragen."
}

export type TeamColor = 'geel' | 'oranje' | 'rood' | 'groen';

export type ResourceType = 'Samenwerking' | 'Tijd' | 'Kennis' | 'Besluitkracht' | 'Materiaal';

export interface Skill {
  id: string;
  name: string;
  rewards: ResourceType[];
}

export interface Question {
  id: string;
  text: string;
  options: string[];
  correctIndex: number;
}

export interface TeamStats {
  completedSkills: string[];
  usedQuestionIds: string[];
  resources: Record<ResourceType, number>;
}

export type AppScreen = 'setup-own' | 'setup-target' | 'dashboard' | 'skills' | 'questions' | 'summary';

import { Skill, Question } from './types';

export const SKILLS: Skill[] = [
  { id: '1', name: 'Buik → rug draaien', rewards: ['Samenwerking', 'Tijd'] },
  { id: '2', name: 'Stabiele zijligging', rewards: ['Samenwerking', 'Tijd'] },
  { id: '3', name: 'AED-elektrodes plakken', rewards: ['Kennis', 'Besluitkracht'] },
  { id: '4', name: 'Reanimatie', rewards: ['Tijd', 'Besluitkracht'] },
  { id: '5', name: 'Pleisters plakken', rewards: ['Materiaal', 'Tijd'] },
  { id: '6', name: 'Steunverband aanleggen', rewards: ['Materiaal', 'Samenwerking'] },
  { id: '7', name: 'Dekenrol aanleggen', rewards: ['Materiaal', 'Samenwerking'] },
  { id: '8', name: 'Wond steriel afdekken', rewards: ['Materiaal', 'Tijd'] },
];

export const ALL_QUESTIONS: Question[] = [
  {
    id: 'q1',
    text: 'Wat is de eerste stap bij het benaderen van een slachtoffer?',
