    correctIndex: 1,
  },
  {
    id: 'q2',
    text: 'Hoeveel borstcompressies geef je bij een volwassene tijdens reanimatie?',
    options: ['15', '20', '30', '50'],
    correctIndex: 2,
  },
  {
    id: 'q3',
