const getTeamColorClass = (team: TeamColor) => {
  switch (team) {
    case 'geel': return 'bg-yellow-400';
    case 'oranje': return 'bg-orange-500';
    case 'rood': return 'bg-red-500';
    case 'groen': return 'bg-green-500';
  }
};

export default Dashboard;

import React, { useState } from 'react';
import { TeamColor, Skill } from '../types';
import { SKILLS } from '../constants';

interface Props {
  targetTeam: TeamColor;
  completedSkills: string[];
  onSkillComplete: (id: string) => void;
  onBack: () => void;
}

const SkillsAssessment: React.FC<Props> = ({ targetTeam, completedSkills, onSkillComplete, onBack }) => {
  // Tracking student checkboxes locally for skills not yet completed
  const [skillProgress, setSkillProgress] = useState<Record<string, boolean[]>>({});

  const toggleStudent = (skillId: string, index: number) => {
    if (completedSkills.includes(skillId)) return;

    const current = skillProgress[skillId] || [false, false, false];
    const next = [...current];
    next[index] = !next[index];

    setSkillProgress(prev => ({ ...prev, [skillId]: next }));

    if (next.every(v => v === true)) {
      onSkillComplete(skillId);
    }
  };

  const markAll = (skillId: string) => {
    if (completedSkills.includes(skillId)) return;
    onSkillComplete(skillId);
  };

  return (
    <div className="flex flex-col gap-6">
      <div className="flex items-center gap-4">
        <button onClick={onBack} className="p-2 hover:bg-slate-100 rounded-lg">
          <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
        </button>
        <h2 className="text-2xl font-bold text-slate-800">Vaardigheden</h2>
      </div>

      <div className="space-y-4">
        {SKILLS.map((skill) => {
          const isDone = completedSkills.includes(skill.id);
          const progress = skillProgress[skill.id] || [false, false, false];

          return (
            <div 
              key={skill.id} 
              className={`p-4 border-2 rounded-xl transition-all ${isDone ? 'bg-green-50 border-green-200' : 'bg-white border-slate-100 shadow-sm'}`}
            >
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h3 className={`font-bold ${isDone ? 'text-green-800' : 'text-slate-800'}`}>{skill.name}</h3>
                  <p className="text-xs text-slate-500 mt-1">
                    Beloning: <span className="font-semibold text-slate-700">{skill.rewards.join(' + ')}</span>
                  </p>
                </div>
                {isDone ? (
                  <span className="bg-green-500 text-white px-3 py-1 rounded-full text-xs font-bold uppercase">Afgerond</span>
                ) : (
                  <button 
                    onClick={() => markAll(skill.id)}
                    className="text-xs text-blue-600 font-bold hover:underline"
                  >
                    Alle 3 afvinken
                  </button>
                )}
              </div>

              <div className="flex gap-4">
                {[0, 1, 2].map(idx => (
                  <button
                    key={idx}
                    disabled={isDone}
                    onClick={() => toggleStudent(skill.id, idx)}
                    className={`
                      flex-1 py-3 rounded-lg border-2 flex flex-col items-center justify-center transition-all
                      ${isDone || progress[idx] 
                        ? 'bg-green-100 border-green-500 text-green-700' 
                        : 'bg-white border-slate-200 text-slate-400 hover:border-blue-400'}
                    `}
                  >
                    <div className={`w-5 h-5 rounded-full border-2 mb-1 flex items-center justify-center ${isDone || progress[idx] ? 'bg-green-500 border-green-500' : 'border-slate-300'}`}>
                      {(isDone || progress[idx]) && (
                        <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" />
                        </svg>
                      )}
                    </div>
                    <span className="text-[10px] font-bold uppercase tracking-wider">Cursist {idx + 1}</span>
                  </button>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default SkillsAssessment;

import React, { useState, useMemo } from 'react';
import { TeamColor, ResourceType, Question } from '../types';
import { ALL_QUESTIONS } from '../constants';

interface Props {
  targetTeam: TeamColor;
  usedQuestionIds: string[];
  onCorrectAnswer: (id: string, bonus: ResourceType | null) => void;
  onBack: () => void;
}

const QuestionQuiz: React.FC<Props> = ({ targetTeam, usedQuestionIds, onCorrectAnswer, onBack }) => {
  const [step, setStep] = useState<'count' | 'quiz' | 'reward'>('count');
  const [questionCount, setQuestionCount] = useState<number>(3);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [isLocked, setIsLocked] = useState(false);

  // Available questions that haven't been used yet
  const availablePool = useMemo(() => 
    ALL_QUESTIONS.filter(q => !usedQuestionIds.includes(q.id)), 
    [usedQuestionIds]
  );

  // Questions selected for this session
  const activeQuestions = useMemo(() => {
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    return shuffled.slice(0, Math.min(questionCount, shuffled.length));
  }, [availablePool, questionCount]);

  const handleStart = () => {
    if (activeQuestions.length === 0) {
      alert("Geen onbeantwoorde vragen meer over!");
      onBack();
      return;
    }
    setStep('quiz');
  };

  const handleOptionClick = (idx: number) => {
    if (isLocked) return;
    setSelectedOption(idx);
    setIsLocked(true);
  };

  const handleNext = () => {
    const currentQ = activeQuestions[currentIdx];
    const isCorrect = selectedOption === currentQ.correctIndex;

    if (isCorrect) {
      setStep('reward');
    } else {
      goToNextOrFinish();
    }
  };

  const goToNextOrFinish = () => {
    if (currentIdx < activeQuestions.length - 1) {
      setCurrentIdx(prev => prev + 1);
      setSelectedOption(null);
      setIsLocked(false);
      setStep('quiz');
    } else {
      onBack();
    }
  };

  const handleRewardSelect = (res: ResourceType) => {
    const currentQ = activeQuestions[currentIdx];
    onCorrectAnswer(currentQ.id, res);
    goToNextOrFinish();
  };

  if (step === 'count') {
    return (
      <div className="flex flex-col gap-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="p-2 hover:bg-slate-100 rounded-lg">
            <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
            </svg>
          </button>
          <h2 className="text-2xl font-bold text-slate-800">Vrageninstellingen</h2>
        </div>

        <div className="bg-blue-50 border border-blue-200 p-6 rounded-2xl">
          <label className="block text-blue-900 font-bold mb-4">Hoeveel vragen wil je beantwoorden?</label>
          <div className="flex items-center gap-6">
            <button 
              onClick={() => setQuestionCount(Math.max(1, questionCount - 1))}
              className="w-12 h-12 rounded-full bg-blue-600 text-white flex items-center justify-center font-bold text-xl shadow-md"
            > - </button>
            <span className="text-3xl font-bold text-blue-900">{questionCount}</span>
            <button 
              onClick={() => setQuestionCount(Math.min(availablePool.length, questionCount + 1))}
              className="w-12 h-12 rounded-full bg-blue-600 text-white flex items-center justify-center font-bold text-xl shadow-md"
            > + </button>
          </div>
          <p className="mt-4 text-sm text-blue-700 italic">Er zijn nog {availablePool.length} unieke vragen beschikbaar.</p>
        </div>

        <button 
          onClick={handleStart}
          className="w-full bg-blue-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-blue-700 transition-colors shadow-lg"
        >
          Start Quiz
        </button>
      </div>
    );
  }

  if (step === 'reward') {
    return (
      <div className="flex flex-col gap-6 text-center py-8">
        <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4 animate-bounce">
           <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
           </svg>
        </div>
        <h2 className="text-3xl font-extrabold text-slate-900">Goedzo!</h2>
        <p className="text-slate-600">Je hebt 1x <span className="font-bold text-blue-600">Kennis</span> verdiend. Kies nu een tweede kaart naar keuze:</p>

        <div className="grid grid-cols-2 gap-3 mt-4">
          {(['Samenwerking', 'Tijd', 'Besluitkracht', 'Materiaal'] as ResourceType[]).map(res => (
            <button
              key={res}
              onClick={() => handleRewardSelect(res)}
              className="p-4 bg-white border-2 border-slate-200 rounded-xl font-bold hover:border-green-500 hover:bg-green-50 transition-all text-slate-800"
            >
              {res}
            </button>
          ))}
        </div>
      </div>
    );
  }

  const currentQ = activeQuestions[currentIdx];
  const isCorrect = selectedOption === currentQ.correctIndex;

  return (
    <div className="flex flex-col gap-6">
      <div className="flex justify-between items-center">
        <span className="text-sm font-bold text-slate-500">Vraag {currentIdx + 1} van {activeQuestions.length}</span>
        <button onClick={onBack} className="text-red-500 font-bold text-sm">Stoppen</button>
      </div>

      <div className="bg-white border-2 border-slate-100 p-6 rounded-2xl shadow-sm">
        <h3 className="text-xl font-bold text-slate-800 mb-6">{currentQ.text}</h3>
        <div className="space-y-3">
          {currentQ.options.map((opt, i) => {
            let stateClass = "bg-white border-slate-200 text-slate-700";
            if (isLocked) {
              if (i === currentQ.correctIndex) stateClass = "bg-green-100 border-green-500 text-green-800 font-bold";
              else if (i === selectedOption) stateClass = "bg-red-100 border-red-500 text-red-800";
              else stateClass = "bg-slate-50 border-slate-100 text-slate-400";
            } else if (selectedOption === i) {
              stateClass = "bg-blue-50 border-blue-500 text-blue-800";
            }

            return (
              <button
                key={i}
                disabled={isLocked}
                onClick={() => handleOptionClick(i)}
                className={`w-full text-left p-4 rounded-xl border-2 transition-all ${stateClass}`}
              >
                {opt}
              </button>
            );
          })}
        </div>
      </div>

      {isLocked && (
        <div className="animate-in fade-in slide-in-from-top-2">
          <p className={`text-center font-bold text-lg mb-4 ${isCorrect ? 'text-green-600' : 'text-red-600'}`}>
            {isCorrect ? 'Helemaal goed!' : 'Helaas, dat is onjuist.'}
          </p>
          <button
            onClick={handleNext}
            className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold text-lg shadow-lg"
          >
            {currentIdx < activeQuestions.length - 1 ? 'Volgende Vraag' : 'Afronden'}
          </button>
        </div>
      )}
    </div>
  );
};

